import { useNavigate } from "react-router-dom";

export default function JoinOrCreateHome() {
  const navigate = useNavigate();

  return (
    <main className="min-h-screen bg-[#eadbc9] flex items-center justify-center px-6">
      <section className="w-full max-w-[1200px] flex flex-col items-center text-center -mt-10">
        <h1
          className="text-[#6b4b3e] font-semibold tracking-[0.01em] mb-14"
          style={{
            fontSize: "clamp(2.9rem, 5.2vw, 5rem)",
            lineHeight: 1,
            fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
          }}
        >
          welcome!
        </h1>

        <div className="flex flex-col items-center gap-7 w-full">
          <button
            onClick={() => navigate("/create-home")}
            className="w-[320px] h-[74px] rounded-[22px] bg-[#aab095] text-[#43332c] text-[2rem] leading-none shadow-[inset_0_0_0_1px_rgba(90,62,54,0.28)] hover:brightness-[0.98] active:translate-y-[1px] transition"
            style={{ fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif' }}
          >
            create a home
          </button>

          <button
            onClick={() => navigate("/join-home")}
            className="w-[320px] h-[74px] rounded-[22px] bg-[#aab095] text-[#43332c] text-[2rem] leading-none shadow-[inset_0_0_0_1px_rgba(90,62,54,0.28)] hover:brightness-[0.98] active:translate-y-[1px] transition"
            style={{ fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif' }}
          >
            join a home
          </button>
        </div>
      </section>
    </main>
  );
}
